function localizeEventText(text='',locale='zh'){if(locale!=='zh')return text;return text.replace(/^Validated (\d+) source file\(s\)$/,'已校验 $1 个源文件').replace('Document structure analysis completed','文档结构分析完成').replace('AI translation provider connected','AI 翻译引擎连接成功').replace(/^Processing file (\d+)\/(\d+): /,'正在处理文件 $1/$2：').replace(/^Completed file (\d+)\/(\d+): /,'已完成文件 $1/$2：').replace(/^Parallel batch started: (\d+) files, (\d+) workers$/,'并行批处理已启动：$1 个文件，$2 个工作线程').replace('Quality checks completed for generated files','交付文件质量检查完成').replace(/^Generated (\d+) delivery file\(s\)$/,'已生成 $1 个交付文件').replace('Automatic processing completed','自动处理完成').replace('Choose and configure an AI translation provider.','尚未配置 AI 翻译服务，请先在企业工作台完成设置').replace('Processing job queued','处理任务已创建，正在检查运行条件').replace('处理任务已创建，正在检查运行条件','处理任务已创建，正在检查运行条件')}
function fileTypeClass(name=''){const ext=(name.split('.').pop()||'').toLowerCase();if(ext==='pdf')return'pdf';if(['doc','docx'].includes(ext))return'word';if(['xls','xlsx','csv'].includes(ext))return'excel';if(['ppt','pptx'].includes(ext))return'ppt';if(['png','jpg','jpeg','bmp','tif','tiff'].includes(ext))return'image';return'file'}

function smartPlanForFiles(files=[]){
  const names=files.map(f=>(f.name||'').toLowerCase())
  const exts=names.map(name=>(name.split('.').pop()||'').toLowerCase())
  const hasImage=exts.some(x=>['png','jpg','jpeg','bmp','tif','tiff'].includes(x))
  const hasExplicitScan=names.some(name=>name.endsWith('.pdf')&&/(scan|scanned|扫描|影印|photo)/i.test(name))
  const hasPdf=exts.includes('pdf'),hasZip=exts.includes('zip')
  return {services:(hasImage||hasExplicitScan)?['ocr']:[],ocrAuto:hasImage||hasExplicitScan,ocrSuggested:hasPdf||hasZip,output:'original',hasZip}
}

function App(){
  const [locale,setLocale]=useState(()=>{const saved=localStorage.getItem('da_locale');if(saved&&LANGUAGE_OPTIONS.some(([id])=>id===saved))return saved;const browser=navigator.language||'en';if(browser.startsWith('zh-TW')||browser.startsWith('zh-HK'))return 'zh-TW';return LANGUAGE_OPTIONS.find(([id,,,tag])=>browser.startsWith(tag.split('-')[0]))?.[0]||'en'})
  const [page,setPage]=useState('home'), [mobile,setMobile]=useState(false), [languageOpen,setLanguageOpen]=useState(false), [accountOpen,setAccountOpen]=useState(false)
  const [authToken,setAuthToken]=useState(()=>localStorage.getItem('da_auth_token')||''), [currentUser,setCurrentUser]=useState(null)
  const [files,setFiles]=useState([]), [services,setServices]=useState([])
  const [translationTargets,setTranslationTargets]=useState([]), [outputFormats,setOutputFormats]=useState([])
  const [outputOptions,setOutputOptions]=useState({preserve_layout:true,preserve_formulas:true,preserve_images:true,preserve_comments:true,preserve_links:true,auto_width:false,freeze_header:false})
  const [form,setForm]=useState({name:'',email:'',company:'',requirements:''})
  const [submitting,setSubmitting]=useState(false), [error,setError]=useState(''), [orderStatus,setOrderStatus]=useState(null)
  const [preferences,setPreferences]=useState(()=>{try{return JSON.parse(localStorage.getItem('da_user_preferences')||'{}')}catch{return {}}})
  const t=I18N[locale]||I18N.en
  useEffect(()=>{localStorage.setItem('da_locale',locale);const option=LANGUAGE_OPTIONS.find(([id])=>id===locale);document.documentElement.lang=option?.[3]||'en-US';document.title=t.seoTitle||`Document Automation AI · ${t.lang}`;document.querySelector('meta[name=description]')?.setAttribute('content',t.heroDesc)},[locale,t.lang,t.seoTitle,t.heroDesc])
  useEffect(()=>{if(!authToken){setCurrentUser(null);return}fetch(`${API_BASE}/api/auth/me`,{headers:{Authorization:`Bearer ${authToken}`}}).then(async r=>{const j=await r.json();if(!r.ok)throw new Error();setCurrentUser(j.user)}).catch(()=>{localStorage.removeItem('da_auth_token');setAuthToken('');setCurrentUser(null)})},[authToken])
  useEffect(()=>{const close=e=>{if(!e.target.closest('.language-menu'))setLanguageOpen(false)};const esc=e=>{if(e.key==='Escape')setLanguageOpen(false)};document.addEventListener('pointerdown',close);document.addEventListener('keydown',esc);return()=>{document.removeEventListener('pointerdown',close);document.removeEventListener('keydown',esc)}},[])
  useEffect(()=>{const sync=e=>setPreferences(e?.detail||(()=>{try{return JSON.parse(localStorage.getItem('da_user_preferences')||'{}')}catch{return {}}})());window.addEventListener('da-preferences-updated',sync);return()=>window.removeEventListener('da-preferences-updated',sync)},[])
  useEffect(()=>{const q=new URLSearchParams(window.location.search);if(['paypal-return','demo','cancelled'].includes(q.get('payment')))setPage('billing')},[])
  useEffect(()=>{if(page!=='order')return;const p=preferences||{};if(p.targetLanguage)setTranslationTargets([p.targetLanguage]);if(p.outputFormat&&p.outputFormat!=='original'){setServices(v=>[...new Set([...v,'conversion'])]);setOutputFormats([p.outputFormat])}const bilingual=p.bilingualLayout!=='target-only';setOutputOptions(v=>({...v,preserve_layout:true,bilingual_layout:p.bilingualLayout||'vertical',ocr_mode:p.ocrMode||'standard',translation_style:p.translationStyle||'technical',knowledge_base:p.knowledgeBase||'none',page_size:p.pageSize||'A4',quality_mode:p.qualityMode||'balanced',auto_quality:p.autoQuality!==false,auto_correct:p.autoCorrect!==false,bilingual}))},[page,preferences])
  const totalSize=useMemo(()=>files.reduce((s,f)=>s+f.size,0),[files])
  const addFiles=list=>setFiles(prev=>{const seen=new Set(prev.map(f=>`${f.name}-${f.size}`));return [...prev,...[...list].filter(f=>!seen.has(`${f.name}-${f.size}`))]})
  const smartPlan=useMemo(()=>smartPlanForFiles(files),[files])
  useEffect(()=>{if(!files.length){setServices([]);setTranslationTargets([]);setOutputFormats([]);setOutputOptions({preserve_layout:true,preserve_formulas:true,preserve_images:true,preserve_comments:true,preserve_links:true,auto_width:false,freeze_header:false});return}if(smartPlan.ocrAuto)setServices(current=>[...new Set(['ocr',...current])])},[files.length,smartPlan.ocrAuto])
  async function submitOrder(e){
    e.preventDefault();setError('')
    if(!files.length)return setError(t.fileRequired)
    if(services.includes('translation')&&!translationTargets.length)return setError(t.languageRequired)
    if(services.includes('conversion')&&!outputFormats.length)return setError(t.formatRequired)
    if(!form.name.trim()||!form.email.trim())return setError(t.contactRequired)
    const resolvedFormats=services.includes('conversion')?outputFormats:['original'];const translation={source_language:'auto',target_language:translationTargets[0]||'en',targets:translationTargets};const conversion={formats:resolvedFormats,options:outputOptions}
    setSubmitting(true)
    const controller=new AbortController();const timeout=setTimeout(()=>controller.abort(),900000)
    try{
      let r
      if(files.some(f=>f.size>3*1024*1024)||totalSize>3*1024*1024){
        const uploadIds=[];const chunkSize=2*1024*1024
        for(const file of files){
          let init=await fetch(`${API_BASE}/api/uploads/init`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({filename:file.name,size_bytes:file.size,content_type:file.type||'application/octet-stream'}),signal:controller.signal});let meta=await init.json();if(!init.ok)throw new Error(meta.detail||t.submitFailed)
          for(let offset=0,index=0;offset<file.size;offset+=chunkSize,index++){const part=file.slice(offset,Math.min(file.size,offset+chunkSize));const cr=await fetch(`${API_BASE}/api/uploads/${meta.upload_id}/chunks/${index}`,{method:'PUT',headers:{'Content-Type':'application/octet-stream'},body:part,signal:controller.signal});const cj=await cr.json();if(!cr.ok)throw new Error(cj.detail||t.submitFailed)}
          const done=await fetch(`${API_BASE}/api/uploads/${meta.upload_id}/complete`,{method:'POST',signal:controller.signal});const dj=await done.json();if(!done.ok)throw new Error(dj.detail||t.submitFailed);uploadIds.push(meta.upload_id)
        }
        r=await fetch(`${API_BASE}/api/orders/from-uploads`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({upload_ids:uploadIds,...form,services:services.length?services:['standard'],translation,conversion}),signal:controller.signal})
      }else{
        const data=new FormData();files.forEach(f=>data.append('files',f));Object.entries(form).forEach(([k,v])=>data.append(k,v));data.append('services',JSON.stringify(services.length?services:['standard']));data.append('translation_json',JSON.stringify(translation));data.append('conversion_json',JSON.stringify(conversion));r=await fetch(`${API_BASE}/api/orders`,{method:'POST',body:data,signal:controller.signal})
      }
      const raw=await r.text();let j={};try{j=raw?JSON.parse(raw):{}}catch{j={detail:raw}}if(!r.ok)throw new Error(j.detail||t.submitFailed);setOrderStatus({...j,email:form.email,services:(services.length?services:['standard']),translation_targets:translationTargets,output_formats:(services.includes('conversion')?outputFormats:['original'])});setPage('status')}
    catch(err){setError(err.name==='AbortError'?(document.documentElement.lang.startsWith('zh')?'云端处理超过15分钟未完成，请检查文件规模、AI 配置或后端日志后重试。':'Cloud processing timed out after 15 minutes. Check file size, AI settings, or backend logs and retry.'):(err.message||t.submitFailed))}finally{clearTimeout(timeout);setSubmitting(false)}
  }
  return <div className="app-shell">
    <header className="topbar"><button className="brand" onClick={()=>setPage('home')}><span className="brand-mark">DA</span><span><b>Document Automation AI</b><small>{t.brandSubtitle}</small></span></button>
      <nav className={mobile?'nav open':'nav'}><a href="#platform" onClick={()=>{setPage('home');setMobile(false)}}>{document.documentElement.lang.startsWith('zh')?'产品能力':'Product'}</a><a href="#workflow" onClick={()=>{setPage('home');setMobile(false)}}>{document.documentElement.lang.startsWith('zh')?'解决方案':'Solutions'}</a><a href="#pricing" onClick={()=>{setPage('home');setMobile(false)}}>{t.pricing}</a><button className="nav-link-button" onClick={()=>{setPage('knowledge');setMobile(false)}}>{document.documentElement.lang.startsWith('zh')?'资源':'Resources'}</button></nav><div className="auth-nav">{currentUser?<div className="account-menu"><button className="account-trigger" onClick={()=>setAccountOpen(v=>!v)}><span>{(currentUser.name||currentUser.email||'U').slice(0,1).toUpperCase()}</span><b>{currentUser.name||currentUser.email}</b><ChevronDown size={15}/></button>{accountOpen&&<div className="account-popover"><button onClick={()=>{setPage('dashboard');setAccountOpen(false)}}>▦ {document.documentElement.lang.startsWith('zh')?'工作台':'Workspace'}</button><button onClick={()=>{setPage('account');setAccountOpen(false)}}>◉ {document.documentElement.lang.startsWith('zh')?'我的账户':'My account'}</button><button onClick={()=>{setPage('billing');setAccountOpen(false)}}>◇ {document.documentElement.lang.startsWith('zh')?'钱包与套餐':'Wallet & plans'}</button><button onClick={()=>{setPage('projects');setAccountOpen(false)}}>▣ {document.documentElement.lang.startsWith('zh')?'项目中心':'Project center'}</button><button onClick={()=>{setPage('processing');setAccountOpen(false)}}>≡ {document.documentElement.lang.startsWith('zh')?'真实处理中心':'Processing center'}</button><button onClick={()=>{setPage('settings');setAccountOpen(false)}}>⚙ {document.documentElement.lang.startsWith('zh')?'设置':'Settings'}</button><button className="danger" onClick={()=>{fetch(`${API_BASE}/api/auth/logout`,{method:'POST',headers:{Authorization:`Bearer ${authToken}`}});localStorage.removeItem('da_auth_token');setAuthToken('');setCurrentUser(null);setAccountOpen(false);setPage('home')}}>{document.documentElement.lang.startsWith('zh')?'退出登录':'Sign out'}</button></div>}</div>:<><button className="sign-in-link" onClick={()=>setPage('login')}>{document.documentElement.lang.startsWith('zh')?'登录':'Sign in'}</button><button className="nav-primary auth-register" onClick={()=>setPage('register')}>{document.documentElement.lang.startsWith('zh')?'免费开始':'Start free'}</button></>}</div>
      <div className="language-menu"><button type="button" className="language-switch" aria-label={t.languageLabel} aria-haspopup="menu" aria-expanded={languageOpen} onClick={e=>{e.stopPropagation();setLanguageOpen(v=>!v)}}><Languages size={17}/><span>{t.lang}</span><ChevronDown size={14} className={languageOpen?'rotated':''}/></button>{languageOpen&&<div className="language-popover" role="menu">{LANGUAGE_OPTIONS.map(([id,flag,label])=><button type="button" role="menuitemradio" aria-checked={locale===id} className={locale===id?'active':''} key={id} onClick={()=>{setLocale(id);setLanguageOpen(false)}}><span><i className="language-flag">{flag}</i>{label}</span>{locale===id&&<Check size={16}/>}</button>)}</div>}</div>
      <button className="menu" onClick={()=>setMobile(!mobile)}>{mobile?<X/>:<Menu/>}</button></header>
    {page==='home'&&<Home t={t} setPage={setPage} locale={locale} authToken={authToken} currentUser={currentUser}/>} {page==='order'&&<PageErrorBoundary locale={locale} onBack={()=>setPage('home')}><OrderCenter {...{t,files,addFiles,setFiles,totalSize,services,setServices,translationTargets,setTranslationTargets,outputFormats,setOutputFormats,outputOptions,setOutputOptions,form,setForm,submitOrder,submitting,error,setPage,smartPlan,preferences,currentUser}}/></PageErrorBoundary>} {page==='status'&&<OrderStatus t={t} data={orderStatus} setPage={setPage}/>} {page==='projects'&&<ProjectCenter locale={locale} setPage={setPage} authToken={authToken}/>} {page==='dashboard'&&<Dashboard t={t} setPage={setPage} authToken={authToken}/>} {page==='processing'&&<ProcessingCenter t={t} setPage={setPage} authToken={authToken}/>} {page==='knowledge'&&<KnowledgeCenter t={t} setPage={setPage}/>} {page==='billing'&&<PaymentCenter t={t} setPage={setPage} locale={locale} authToken={authToken} currentUser={currentUser}/>} {page==='acceptance'&&<AcceptanceCenter setPage={setPage}/>} {page==='login'&&<AuthPage mode="login" locale={locale} setPage={setPage} setAuthToken={setAuthToken} setCurrentUser={setCurrentUser}/>} {page==='register'&&<AuthPage mode="register" locale={locale} setPage={setPage} setAuthToken={setAuthToken} setCurrentUser={setCurrentUser}/>} {page==='account'&&<AccountPage locale={locale} user={currentUser} authToken={authToken} setPage={setPage}/>} {page==='settings'&&<SettingsPage locale={locale} user={currentUser} setPage={setPage}/>}  
    <footer className="enterprise-footer"><div className="footer-brand-block"><div className="brand footer-brand"><span className="brand-mark">DA</span><span><b>Document Automation AI</b><small>Version {VERSION}</small></span></div><p>{t.footer}</p></div><div className="footer-links"><div><b>{document.documentElement.lang.startsWith('zh')?'产品':'Product'}</b><span>OCR</span><span>{document.documentElement.lang.startsWith('zh')?'文档翻译':'Translation'}</span><span>{document.documentElement.lang.startsWith('zh')?'格式转换':'Conversion'}</span></div><div><b>{document.documentElement.lang.startsWith('zh')?'平台':'Platform'}</b><span>{document.documentElement.lang.startsWith('zh')?'价格方案':'Pricing'}</span><span>API</span><span>{document.documentElement.lang.startsWith('zh')?'AI 知识库':'AI Knowledge Base'}</span></div><div><b>{document.documentElement.lang.startsWith('zh')?'支持':'Support'}</b><span>{document.documentElement.lang.startsWith('zh')?'帮助中心':'Help Center'}</span><span>{document.documentElement.lang.startsWith('zh')?'服务状态':'System Status'}</span><span>{document.documentElement.lang.startsWith('zh')?'联系我们':'Contact'}</span></div></div><div className="footer-bottom"><span>© 2026 Document Automation AI</span><span>Privacy · Terms · Cookies</span></div></footer>
  </div>
}

class PageErrorBoundary extends Component {
  constructor(props){super(props);this.state={hasError:false,error:null}}
  static getDerivedStateFromError(error){return {hasError:true,error}}
  componentDidCatch(error,info){console.error('Page render error:',error,info)}
  render(){
    if(!this.state.hasError)return this.props.children
    const zh=String(this.props.locale||'').startsWith('zh')
    return <main className="page-wrap"><section className="processing-auth"><AlertTriangle/><h1>{zh?'页面加载失败':'Page failed to load'}</h1><p>{zh?'页面发生异常，但系统没有整页白屏。请返回首页后重试。':'An unexpected error occurred. Return home and try again.'}</p><button onClick={()=>{this.setState({hasError:false,error:null});this.props.onBack?.()}}>{zh?'返回首页':'Back home'}</button></section></main>
  }
}

